import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"WebDAV Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/webdav.md","filePath":"bn-BD/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"bn-BD/upload/webdav.md"};function c(p,e,h,u,b,m){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-channel-যোগ-করা" tabindex="-1">WebDAV Channel যোগ করা <a class="header-anchor" href="#webdav-channel-যোগ-করা" aria-label="Permalink to &quot;WebDAV Channel যোগ করা&quot;">​</a></h1><h2 id="কখন-সবচেয়ে-উপযোগী" tabindex="-1">কখন সবচেয়ে উপযোগী <a class="header-anchor" href="#কখন-সবচেয়ে-উপযোগী" aria-label="Permalink to &quot;কখন সবচেয়ে উপযোগী&quot;">​</a></h2><p>WebDAV channel ব্যবহার করুন যখন:</p><ul><li>আপনার NAS, cloud drive বা object storage service WebDAV endpoint দেয়।</li><li>Uploaded images নিজের WebDAV directory-তে সংরক্ষণ করতে চান।</li><li>Credentials দীর্ঘমেয়াদে frontend-এ expose না করে D1 <code>upload_channels</code> table-এ save করতে চান।</li></ul><h2 id="শুরু-করার-আগে-যা-লাগবে" tabindex="-1">শুরু করার আগে যা লাগবে <a class="header-anchor" href="#শুরু-করার-আগে-যা-লাগবে" aria-label="Permalink to &quot;শুরু করার আগে যা লাগবে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV URL, যেমন <code>https://nas.example.com/dav</code>।</td></tr><tr><td>Username</td><td>WebDAV service-এ sign in করতে লাগে।</td></tr><tr><td>Password</td><td>WebDAV service-এ sign in করতে লাগে।</td></tr><tr><td>Authentication mode</td><td>Default <code>Basic</code>। Server চাইলে শুধু <code>Digest</code> বা auto negotiation ব্যবহার করুন।</td></tr><tr><td>Storage directory</td><td>Files সংরক্ষণের directory। Default <code>imgbed</code>।</td></tr></tbody></table><h2 id="কোথায়-যোগ-করবেন" tabindex="-1">কোথায় যোগ করবেন <a class="header-anchor" href="#কোথায়-যোগ-করবেন" aria-label="Permalink to &quot;কোথায় যোগ করবেন&quot;">​</a></h2><ol><li>System Settings খুলুন।</li><li>Upload Settings-এ যান।</li><li>উপরের ডান পাশে Add Channel ক্লিক করুন।</li><li><code>WebDAV</code> নির্বাচন করুন।</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>কাজ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>WebDAV channel-এর চেনা যায় এমন নাম, যেমন <code>koofr</code> বা <code>nas</code>।</td><td>Yes</td></tr><tr><td>Endpoint</td><td><code>https://</code>-সহ full WebDAV endpoint।</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username।</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password।</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>সাধারণত <code>Basic</code>; server digest authentication চাইলে <code>Digest</code> ব্যবহার করুন।</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Files যেখানে রাখা হবে। Default <code>imgbed</code>।</td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-তৈরি-করুন" tabindex="-1">1. App Password তৈরি করুন <a class="header-anchor" href="#_1-app-password-তৈরি-করুন" aria-label="Permalink to &quot;1. App Password তৈরি করুন&quot;">​</a></h3><p>Account security settings খুলুন, application passwords খুঁজুন এবং নতুন app password তৈরি করুন।</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>তৈরি হওয়ার পর নতুন app password copy করে save করুন। সাধারণত এটি একবারই দেখানো হয়।</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-imgbed-এ-webdav-configuration-পূরণ-করুন" tabindex="-1">2. ImgBed-এ WebDAV Configuration পূরণ করুন <a class="header-anchor" href="#_2-imgbed-এ-webdav-configuration-পূরণ-করুন" aria-label="Permalink to &quot;2. ImgBed-এ WebDAV Configuration পূরণ করুন&quot;">​</a></h3><p>ImgBed-এ ফিরে WebDAV channel যোগ করুন:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> থেকে পাওয়া WebDAV URL।</td></tr><tr><td>Username</td><td>আপনার WebDAV username।</td></tr><tr><td>Password</td><td>সদ্য তৈরি করা app password।</td></tr><tr><td>Authentication mode</td><td>বেশিরভাগ ক্ষেত্রে <code>Basic</code> দিয়ে শুরু করুন।</td></tr><tr><td>Storage directory</td><td>Default <code>imgbed</code>; চাইলে custom directory ব্যবহার করতে পারেন।</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="large-file-upload-behavior" tabindex="-1">Large File Upload Behavior <a class="header-anchor" href="#large-file-upload-behavior" aria-label="Permalink to &quot;Large File Upload Behavior&quot;">​</a></h2><p>WebDAV channel এখন real session-based chunked upload ব্যবহার করে।</p><p>ছোট files একটিমাত্র complete file হিসেবে upload হয়। 64 MiB-এর বড় files automatically প্রায় 10 MiB করে chunks-এ ভাগ হয়ে remote chunk directory-তে upload হয়।</p><p>WebDAV service-এর <code>partial update</code> বা offset-based writes support করার দরকার নেই। ImgBed remote server-এ chunks merge করে একটিমাত্র বড় file বানায় না। এর বদলে chunk manifest store করে এবং file request হলে chunks ক্রমানুসারে পড়ে।</p><p>বাস্তবে:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB বা কম</td><td>Normal upload</td><td>একটি complete file</td></tr><tr><td>64 MiB-এর বেশি</td><td>Real session chunked upload</td><td>Multiple chunk files থাকা chunk directory</td></tr></tbody></table><p>Chunk directory শুধু remote storage layout-এ প্রভাব ফেলে। ImgBed-এর file URL বদলায় না। Users আগের মতো original <code>/file/...</code> link দিয়েই file access করে।</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings খুলুন।</li><li>Add Channel ক্লিক করুন।</li><li><code>WebDAV</code> নির্বাচন করুন।</li><li>চেনা যায় এমন channel name দিন, যেমন <code>koofr</code>।</li><li>WebDAV endpoint দিন, যেমন <code>https://app.koofr.net/dav/Koofr</code>।</li><li>Username এবং password দিন।</li><li>Default হিসেবে authentication mode <code>Basic</code> রাখুন।</li><li>Storage directory <code>imgbed</code> রাখুন, বা নিজের directory দিন।</li><li>Save ক্লিক করুন।</li><li>Save করার পর channel card check করুন, capacity available হলে query করুন, এবং test file upload করুন।</li></ol><h2 id="কীভাবে-যাচাই-করবেন" tabindex="-1">কীভাবে যাচাই করবেন <a class="header-anchor" href="#কীভাবে-যাচাই-করবেন" aria-label="Permalink to &quot;কীভাবে যাচাই করবেন&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>কীভাবে যাচাই করবেন</th></tr></thead><tbody><tr><td>Channel card দেখা যায়</td><td>Save করার পর Upload Settings পেজে WebDAV channel card দেখা উচিত।</td></tr><tr><td>Channel enabled</td><td>Card-এর upper-right switch on থাকা উচিত।</td></tr><tr><td>Credentials save হয়েছে</td><td>Detail view-তে Endpoint, username, authentication mode এবং storage directory দেখা উচিত।</td></tr><tr><td>Small file upload কাজ করে</td><td>Test image upload করে WebDAV directory-তে file এসেছে কি না দেখুন।</td></tr><tr><td>Large file rule কাজ করে</td><td>64 MiB-এর বড় files chunked upload ব্যবহার করে এবং remote chunk directory তৈরি করে।</td></tr><tr><td>Capacity query কাজ করে</td><td>Server capacity information support করলে query used এবং total capacity দেখাবে।</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="large-webdav-files-কেন-chunk-directory-তৈরি-করে" tabindex="-1">Large WebDAV files কেন chunk directory তৈরি করে? <a class="header-anchor" href="#large-webdav-files-কেন-chunk-directory-তৈরি-করে" aria-label="Permalink to &quot;Large WebDAV files কেন chunk directory তৈরি করে?&quot;">​</a></h3><p>এটাই large files-এর বর্তমান storage method।</p><p>64 MiB-এর বড় files একটিমাত্র large remote file-এ merge হয় না। এগুলো chunk directory হিসেবে store হয়। ImgBed chunk manifest record করে এবং content ফেরত দেওয়ার সময় chunks ক্রমানুসারে পড়ে।</p><h3 id="large-file-upload-fail-হলে-আগে-কী-দেখব" tabindex="-1">Large file upload fail হলে আগে কী দেখব? <a class="header-anchor" href="#large-file-upload-fail-হলে-আগে-কী-দেখব" aria-label="Permalink to &quot;Large file upload fail হলে আগে কী দেখব?&quot;">​</a></h3><p>আগে Endpoint, username, password এবং storage directory check করুন। তারপর WebDAV service directory creation, file writing এবং file reading allow করে কি না confirm করুন।</p><p>Capacity query fail হলেও small file upload কাজ করলে server হয়তো capacity reporting support করে না বা restrict করে। তার মানে upload unavailable, এমন নয়।</p><h3 id="কোন-authentication-mode-ব্যবহার-করব" tabindex="-1">কোন authentication mode ব্যবহার করব? <a class="header-anchor" href="#কোন-authentication-mode-ব্যবহার-করব" aria-label="Permalink to &quot;কোন authentication mode ব্যবহার করব?&quot;">​</a></h3><p><code>Basic</code> দিয়ে শুরু করুন।</p><p>Server explicitly digest authentication চাইলে <code>Digest</code> ব্যবহার করুন।</p><p>নিশ্চিত না হলে automatic negotiation ব্যবহার করুন।</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username এবং password প্রস্তুত করুন</span></span>
<span class="line"><span>-&gt; Upload Settings খুলুন</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; Endpoint / username / password দিন</span></span>
<span class="line"><span>-&gt; Default হিসেবে authentication mode Basic রাখুন</span></span>
<span class="line"><span>-&gt; Default হিসেবে storage directory imgbed রাখুন</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Test file upload করুন</span></span></code></pre></div>`,45)])])}const k=r(s,[["render",c]]);export{y as __pageData,k as default};
